def dörrvakt(namn = "Alex", ålder = 17, åldersgräns = 18): 
  if ålder < åldersgräns: 
    print("Tyvärr " + namn + ", du får vänta tills du är", åldersgräns, ".") 

  else: 
    print("Välkommen in " + namn) 

dörrvakt("Nisse", 22)
dörrvakt()
dörrvakt(ålder = 16, åldersgräns = 20)
dörrvakt("Chris", 14, 15)
